	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE
);

CREATE TABLE employees (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	contact_id CHAR(32) NOT NULL, 
	employee_number VARCHAR(32) NOT NULL, 
	payee_id_bms CHAR(32) NOT NULL, 
	previous_payee_id VARCHAR(50), 
	tfn_encrypted TEXT, 
	tfn_status VARCHAR(16) DEFAULT 'NOT_PROVIDED' NOT NULL, 
	dob DATE, 
	start_date DATE NOT NULL, 
	end_date DATE, 
	termination_reason VARCHAR(1), 
	address_line1 VARCHAR, 
	address_line2 VARCHAR, 
	suburb VARCHAR(64), 
	state VARCHAR(8), 
	postcode VARCHAR(8), 
	country_code VARCHAR(2) DEFAULT 'AU' NOT NULL, 
	employment_basis VARCHAR(1) NOT NULL, 
	tax_treatment_code VARCHAR(6), 
	claims_tax_free_threshold BOOLEAN DEFAULT 'false' NOT NULL, 
	is_australian_resident BOOLEAN DEFAULT 'true' NOT NULL, 
	study_training_support_loan BOOLEAN DEFAULT 'false' NOT NULL, 
	working_holiday_maker BOOLEAN DEFAULT 'false' NOT NULL, 
	whm_country_code VARCHAR(2), 
	income_stream_type VARCHAR(3) DEFAULT 'SAW' NOT NULL, 
	payg_branch_code VARCHAR(3), 
	bsb_encrypted TEXT, 
	account_number_encrypted TEXT, 
	account_name_encrypted TEXT, 
	super_fund_id CHAR(32), 
	super_member_number VARCHAR(64), 
	payslip_email VARCHAR, 
	payslip_delivery VARCHAR(6) DEFAULT 'EMAIL' NOT NULL, 
	pay_frequency VARCHAR(11) DEFAULT 'WEEKLY' NOT NULL, 
	pay_basis VARCHAR(6) DEFAULT 'HOURLY' NOT NULL, 
	base_rate NUMERIC(10, 4) NOT NULL, 
	weekly_hours NUMERIC(5, 2) DEFAULT '38.00' NOT NULL, 
	notes TEXT, 
	extra JSON, 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_employees_company_number UNIQUE (company_id, employee_number), 
	CONSTRAINT uq_employees_contact_id UNIQUE (contact_id), 
	CONSTRAINT ck_employees_end_after_start CHECK (end_date IS NULL OR end_date >= start_date), 
	CONSTRAINT ck_employees_termination_needs_end_date CHECK (termination_reason IS NULL OR end_date IS NOT NULL), 
	CONSTRAINT ck_employees_whm_country_required CHECK (working_holiday_maker = false OR whm_country_code IS NOT NULL), 
	CONSTRAINT ck_employees_salary_needs_weekly_hours CHECK (pay_basis = 'HOURLY' OR weekly_hours > 0), 
	CONSTRAINT ck_employees_base_rate_nonneg CHECK (base_rate >= 0), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(contact_id) REFERENCES contacts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(super_fund_id) REFERENCES super_funds (id) ON DELETE RESTRICT
);

CREATE TABLE expense_lines (
	id CHAR(32) NOT NULL, 
	expense_id CHAR(32) NOT NULL, 
	line_no INTEGER NOT NULL, 
	description TEXT NOT NULL, 
	account_id CHAR(32) NOT NULL, 
	tax_code_id CHAR(32), 
	quantity NUMERIC(18, 4) NOT NULL, 
	unit_price NUMERIC(18, 4) NOT NULL, 
	discount_pct NUMERIC(6, 2) NOT NULL, 
	line_subtotal NUMERIC(18, 2) NOT NULL, 
	line_tax NUMERIC(18, 2) NOT NULL, 
	line_total NUMERIC(18, 2) NOT NULL, 
	project_id CHAR(32), 
	PRIMARY KEY (id), 
	FOREIGN KEY(expense_id) REFERENCES expenses (id) ON DELETE CASCADE, 
	FOREIGN KEY(account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tax_code_id) REFERENCES tax_codes (id) ON DELETE SET NULL, 
	FOREIGN KEY(project_id) REFERENCES projects (id) ON DELETE SET NULL
);

CREATE TABLE expenses (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	contact_id CHAR(32), 
	one_off_vendor_id CHAR(32), 
	payment_account_id CHAR(32) NOT NULL, 
	number VARCHAR(32), 
	reference VARCHAR(64), 
	expense_date DATE NOT NULL, 
	status VARCHAR(6) NOT NULL, 
	subtotal NUMERIC(18, 2) NOT NULL, 
	tax_total NUMERIC(18, 2) NOT NULL, 
	total NUMERIC(18, 2) NOT NULL, 
	currency VARCHAR(3) NOT NULL, 
	fx_rate NUMERIC(18, 8) NOT NULL, 
	base_subtotal NUMERIC(18, 2) NOT NULL, 
	base_tax_total NUMERIC(18, 2) NOT NULL, 
	base_total NUMERIC(18, 2) NOT NULL, 
	notes TEXT, 
	posted_at DATETIME, 
	posted_by VARCHAR, 
	version INTEGER NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	journal_entry_id CHAR(32), 
	void_journal_entry_id CHAR(32), 
	external_id VARCHAR(255), 
	external_source VARCHAR(64), 
	external_etag VARCHAR(255), 
	external_payload JSON, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_expenses_company_number UNIQUE (company_id, number), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(contact_id) REFERENCES contacts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(one_off_vendor_id) REFERENCES one_off_vendors (id) ON DELETE RESTRICT, 
	FOREIGN KEY(payment_account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL, 
	FOREIGN KEY(void_journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL
);

CREATE TABLE fixed_assets (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	version INTEGER NOT NULL, 
	code VARCHAR(32) NOT NULL, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	cost_account_id CHAR(32) NOT NULL, 
	accum_dep_account_id CHAR(32) NOT NULL, 
	dep_expense_account_id CHAR(32) NOT NULL, 
	depreciation_model_id VARCHAR(64) NOT NULL, 
	tax_model_id VARCHAR(64), 
	purchase_date DATE NOT NULL, 
	in_service_date DATE NOT NULL, 
	cost NUMERIC(18, 2) NOT NULL, 
	residual_value NUMERIC(18, 2) DEFAULT '0' NOT NULL, 
	last_depreciation_posted_through DATE, 
	status VARCHAR(16) DEFAULT 'active' NOT NULL, 
	disposal_date DATE, 
	disposal_proceeds NUMERIC(18, 2), 
	disposal_journal_id CHAR(32), 
	parent_asset_id CHAR(32), 
	serial_number VARCHAR, 
	manufacturer VARCHAR, 
	model_number VARCHAR, 
	location VARCHAR, 
	custody_person VARCHAR, 
	warranty_end DATE, 
	purchase_contact_id CHAR(32), 
	extra JSON, 
	archived_at DATETIME, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(cost_account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(accum_dep_account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(dep_expense_account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(depreciation_model_id) REFERENCES depreciation_models (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tax_model_id) REFERENCES depreciation_models (id) ON DELETE RESTRICT, 
	FOREIGN KEY(disposal_journal_id) REFERENCES journal_entries (id) ON DELETE SET NULL, 
	FOREIGN KEY(parent_asset_id) REFERENCES fixed_assets (id) ON DELETE SET NULL, 
	FOREIGN KEY(purchase_contact_id) REFERENCES contacts (id) ON DELETE SET NULL
);

CREATE TABLE fx_rate_snapshots (
	id CHAR(32) NOT NULL, 
	rate_date DATE NOT NULL, 
	source VARCHAR(16) NOT NULL, 
	from_ccy VARCHAR(3) NOT NULL, 
	to_ccy VARCHAR(3) NOT NULL, 
	rate NUMERIC(18, 8) NOT NULL, 
	fetched_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_fx_rate_snapshots_key UNIQUE (rate_date, source, from_ccy, to_ccy)
);

CREATE TABLE idempotency_keys (
	"key" CHAR(32) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	response_body JSON NOT NULL, 
	response_status INTEGER NOT NULL, 
	PRIMARY KEY ("key")
);

CREATE TABLE idempotency_records (
	idempotency_key TEXT NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	body_sha256 TEXT NOT NULL, 
	response_status INTEGER NOT NULL, 
	response_body BLOB NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (idempotency_key)
);

CREATE TABLE invoice_lines (
	id CHAR(32) NOT NULL, 
	invoice_id CHAR(32) NOT NULL, 
	line_no INTEGER NOT NULL, 
	description TEXT NOT NULL, 
	account_id CHAR(32) NOT NULL, 
	tax_code_id CHAR(32), 
	quantity NUMERIC(18, 4) NOT NULL, 
	unit_price NUMERIC(18, 4) NOT NULL, 
	discount_pct NUMERIC(6, 2) NOT NULL, 
	line_subtotal NUMERIC(18, 2) NOT NULL, 
	line_tax NUMERIC(18, 2) NOT NULL, 
	line_total NUMERIC(18, 2) NOT NULL, 
	project_id CHAR(32), 
	item_id CHAR(32), 
	franking_credit_amount NUMERIC(18, 2), 
	franking_percentage NUMERIC(7, 4), 
	service_start_date DATE, 
	service_end_date DATE, 
	recognized_through_date DATE, 
	margin_acq_cost NUMERIC(18, 2), 
	retention_pct NUMERIC(5, 2) NOT NULL, 
	is_trade_in BOOLEAN NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(invoice_id) REFERENCES invoices (id) ON DELETE CASCADE, 
	FOREIGN KEY(account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tax_code_id) REFERENCES tax_codes (id) ON DELETE SET NULL, 
	FOREIGN KEY(project_id) REFERENCES projects (id) ON DELETE SET NULL, 
	FOREIGN KEY(item_id) REFERENCES items (id) ON DELETE SET NULL
);

CREATE TABLE invoices (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	contact_id CHAR(32) NOT NULL, 
	one_off_customer_id CHAR(32), 
	number VARCHAR(32), 
	issue_date DATE NOT NULL, 
	due_date DATE NOT NULL, 
	status VARCHAR(11) NOT NULL, 
	subtotal NUMERIC(18, 2) NOT NULL, 
	tax_total NUMERIC(18, 2) NOT NULL, 
	total NUMERIC(18, 2) NOT NULL, 
	amount_paid NUMERIC(18, 2) NOT NULL, 
	currency VARCHAR(3) NOT NULL, 
	fx_rate NUMERIC(18, 8) NOT NULL, 
	base_subtotal NUMERIC(18, 2) NOT NULL, 
	base_tax_total NUMERIC(18, 2) NOT NULL, 
	base_total NUMERIC(18, 2) NOT NULL, 
	base_amount_paid NUMERIC(18, 2) NOT NULL, 
	settlement_date DATE, 
	notes TEXT, 
	payment_terms TEXT, 
	sent_at DATETIME, 
	posted_at DATETIME, 
	posted_by VARCHAR, 
	journal_entry_id CHAR(32), 
	void_journal_entry_id CHAR(32), 
	write_off_journal_entry_id CHAR(32), 
	external_id VARCHAR(255), 
	external_source VARCHAR(64), 
	external_etag VARCHAR(255), 
	external_payload JSON, 
	version INTEGER NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	stripe_payment_link TEXT, 
	source_quote_id CHAR(32), 
	PRIMARY KEY (id), 
	CONSTRAINT uq_invoices_company_number UNIQUE (company_id, number), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(contact_id) REFERENCES contacts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(one_off_customer_id) REFERENCES one_off_customers (id) ON DELETE RESTRICT, 
	FOREIGN KEY(journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL, 
	FOREIGN KEY(void_journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL, 
	FOREIGN KEY(write_off_journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(source_quote_id) REFERENCES quotes (id) ON DELETE SET NULL
);

CREATE TABLE items (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	sku VARCHAR(64) NOT NULL, 
	item_type VARCHAR(16) NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	description TEXT, 
	cost_method VARCHAR(16) NOT NULL, 
	on_hand_qty NUMERIC(18, 4) NOT NULL, 
	wac_cost NUMERIC(18, 4) NOT NULL, 
	default_sale_price NUMERIC(18, 4) NOT NULL, 
	inventory_account_id CHAR(32) NOT NULL, 
	cogs_account_id CHAR(32) NOT NULL, 
	income_account_id CHAR(32) NOT NULL, 
	extra JSON, 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_items_company_sku UNIQUE (company_id, sku), 
	CONSTRAINT ck_items_cost_method_valid CHECK (cost_method IN ('WAC')), 
	CONSTRAINT ck_items_item_type_valid CHECK (item_type IN ('inventory', 'service')), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(inventory_account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(cogs_account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(income_account_id) REFERENCES accounts (id) ON DELETE RESTRICT
);

CREATE TABLE journal_entries (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	ref VARCHAR(32) NOT NULL, 
	entry_date DATE NOT NULL, 
	description TEXT, 
	status VARCHAR(16) NOT NULL, 
	posted_at DATETIME, 
	posted_by VARCHAR, 
	reversal_of_id CHAR(32), 
	override_reason TEXT, 
	attachments JSON, 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_journal_entries_company_ref UNIQUE (company_id, ref), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(reversal_of_id) REFERENCES journal_entries (id) ON DELETE SET NULL
);

CREATE TABLE journal_lines (
	id CHAR(32) NOT NULL, 
	entry_id CHAR(32) NOT NULL, 
	line_no INTEGER NOT NULL, 
	account_id CHAR(32) NOT NULL, 
	description TEXT, 
	debit NUMERIC(14, 2) NOT NULL, 
	credit NUMERIC(14, 2) NOT NULL, 
	tax_code_id CHAR(32), 
	gst_amount NUMERIC(14, 2), 
	project_id CHAR(32), 
	department_id CHAR(32), 
	cost_centre_id CHAR(32), 
	franking_credit_amount NUMERIC(14, 2), 
	tax_treatment JSON, 
	PRIMARY KEY (id), 
	FOREIGN KEY(entry_id) REFERENCES journal_entries (id) ON DELETE CASCADE, 
	FOREIGN KEY(account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tax_code_id) REFERENCES tax_codes (id) ON DELETE SET NULL, 
	FOREIGN KEY(project_id) REFERENCES projects (id) ON DELETE SET NULL, 
	FOREIGN KEY(department_id) REFERENCES departments (id) ON DELETE SET NULL, 
	FOREIGN KEY(cost_centre_id) REFERENCES cost_centres (id) ON DELETE SET NULL
);

CREATE TABLE journal_templates (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	name VARCHAR NOT NULL, 
	description TEXT, 
	lines JSON NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT
);

CREATE TABLE leave_accruals (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	balance_id CHAR(32) NOT NULL, 
	kind VARCHAR(6) NOT NULL, 
	hours NUMERIC(10, 2) NOT NULL, 
	pay_run_id CHAR(32), 
	pay_run_line_id CHAR(32), 
	reason TEXT, 
	balance_after NUMERIC(10, 2) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	created_by CHAR(32), 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(balance_id) REFERENCES leave_balances (id) ON DELETE CASCADE, 
	FOREIGN KEY(pay_run_id) REFERENCES pay_runs (id) ON DELETE SET NULL, 
	FOREIGN KEY(pay_run_line_id) REFERENCES pay_run_lines (id) ON DELETE SET NULL, 
	FOREIGN KEY(created_by) REFERENCES users (id) ON DELETE SET NULL
);

CREATE TABLE leave_balances (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	employee_id CHAR(32) NOT NULL, 
	leave_type VARCHAR(12) NOT NULL, 
	balance_hours NUMERIC(10, 2) NOT NULL, 
	opening_balance_hours NUMERIC(10, 2) NOT NULL, 
	opening_balance_as_at DATE, 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_leave_balances_employee_leave_type UNIQUE (employee_id, leave_type), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(employee_id) REFERENCES employees (id) ON DELETE CASCADE
);

CREATE TABLE lodgement_records (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	tax_return_id CHAR(32) NOT NULL, 
	jurisdiction VARCHAR(3) NOT NULL, 
