	PRIMARY KEY (id), 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE CASCADE
);

CREATE TABLE pay_run_lines (
	id CHAR(32) NOT NULL, 
	pay_run_id CHAR(32) NOT NULL, 
	employee_id CHAR(32) NOT NULL, 
	gross NUMERIC(14, 2) NOT NULL, 
	tax NUMERIC(14, 2) NOT NULL, 
	super_amount NUMERIC(14, 2) NOT NULL, 
	net NUMERIC(14, 2) NOT NULL, 
	ordinary_hours NUMERIC(8, 2) DEFAULT '0' NOT NULL, 
	overtime_hours NUMERIC(8, 2) DEFAULT '0' NOT NULL, 
	leave_hours_paid_annual NUMERIC(8, 2) DEFAULT '0' NOT NULL, 
	leave_hours_paid_personal NUMERIC(8, 2) DEFAULT '0' NOT NULL, 
	leave_hours_unpaid NUMERIC(8, 2) DEFAULT '0' NOT NULL, 
	allowances JSON DEFAULT '[]' NOT NULL, 
	deductions JSON DEFAULT '[]' NOT NULL, 
	paid_leave_lines JSON DEFAULT '[]' NOT NULL, 
	lump_sums JSON DEFAULT '{}' NOT NULL, 
	reportable_fringe_benefits JSON DEFAULT '{}' NOT NULL, 
	extra_pay NUMERIC(14, 2) DEFAULT '0' NOT NULL, 
	ytd_gross NUMERIC(14, 2) DEFAULT '0' NOT NULL, 
	ytd_tax NUMERIC(14, 2) DEFAULT '0' NOT NULL, 
	ytd_super NUMERIC(14, 2) DEFAULT '0' NOT NULL, 
	payg_scale_used VARCHAR(32), 
	payg_breakdown JSON, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(pay_run_id) REFERENCES pay_runs (id) ON DELETE CASCADE, 
	FOREIGN KEY(employee_id) REFERENCES employees (id) ON DELETE RESTRICT
);

CREATE TABLE pay_runs (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	period_start DATE NOT NULL, 
	period_end DATE NOT NULL, 
	payment_date DATE NOT NULL, 
	description TEXT, 
	status VARCHAR(16) NOT NULL, 
	journal_id CHAR(32), 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(journal_id) REFERENCES journal_entries (id) ON DELETE SET NULL
);

CREATE TABLE payg_tax_scales (
	id CHAR(32) NOT NULL, 
	scale_no INTEGER NOT NULL, 
	period VARCHAR(11) NOT NULL, 
	earnings_floor NUMERIC(14, 2) NOT NULL, 
	earnings_ceil NUMERIC(14, 2), 
	coef_a NUMERIC(8, 6) NOT NULL, 
	coef_b NUMERIC(14, 6) NOT NULL, 
	effective_from DATE NOT NULL, 
	effective_to DATE, 
	source_doc VARCHAR(256) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_payg_tax_scales_band_ascending CHECK (earnings_ceil IS NULL OR earnings_ceil > earnings_floor), 
	CONSTRAINT ck_payg_tax_scales_dates_ascending CHECK (effective_to IS NULL OR effective_to >= effective_from), 
	CONSTRAINT ck_payg_tax_scales_scale_range CHECK (scale_no >= 1 AND scale_no <= 8), 
	CONSTRAINT ck_payg_tax_scales_coef_a_nonneg CHECK (coef_a >= 0)
);

CREATE TABLE payment_allocations (
	id CHAR(32) NOT NULL, 
	payment_id CHAR(32) NOT NULL, 
	invoice_id CHAR(32), 
	credit_note_id CHAR(32), 
	bill_id CHAR(32), 
	amount NUMERIC(18, 2) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(payment_id) REFERENCES payments (id) ON DELETE CASCADE, 
	FOREIGN KEY(invoice_id) REFERENCES invoices (id) ON DELETE RESTRICT, 
	FOREIGN KEY(credit_note_id) REFERENCES credit_notes (id) ON DELETE RESTRICT, 
	FOREIGN KEY(bill_id) REFERENCES bills (id) ON DELETE RESTRICT
);

CREATE TABLE payments (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	contact_id CHAR(32) NOT NULL, 
	one_off_vendor_id CHAR(32), 
	one_off_customer_id CHAR(32), 
	bank_account_id CHAR(32) NOT NULL, 
	number VARCHAR(32), 
	direction VARCHAR(8) NOT NULL, 
	method VARCHAR(14) NOT NULL, 
	status VARCHAR(6) NOT NULL, 
	payment_date DATE NOT NULL, 
	amount NUMERIC(18, 2) NOT NULL, 
	currency VARCHAR(3) NOT NULL, 
	fx_rate NUMERIC(18, 8) NOT NULL, 
	base_amount NUMERIC(18, 2) NOT NULL, 
	reference VARCHAR(128), 
	notes TEXT, 
	posted_at DATETIME, 
	posted_by VARCHAR, 
	journal_entry_id CHAR(32), 
	void_journal_entry_id CHAR(32), 
	external_id VARCHAR(255), 
	external_source VARCHAR(64), 
	external_etag VARCHAR(255), 
	external_payload JSON, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	version INTEGER NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_payments_company_number UNIQUE (company_id, number), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(contact_id) REFERENCES contacts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(one_off_vendor_id) REFERENCES one_off_vendors (id) ON DELETE RESTRICT, 
	FOREIGN KEY(one_off_customer_id) REFERENCES one_off_customers (id) ON DELETE RESTRICT, 
	FOREIGN KEY(bank_account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL, 
	FOREIGN KEY(void_journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT
);

CREATE TABLE period_locks (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	locked_through DATE NOT NULL, 
	locked_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	locked_by VARCHAR, 
	reason TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE
);

CREATE TABLE permissions (
	code VARCHAR(64) NOT NULL, 
	description VARCHAR(255) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (code)
);

CREATE TABLE projects (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	code VARCHAR(32) NOT NULL, 
	name VARCHAR(128) NOT NULL, 
	status VARCHAR(16) NOT NULL, 
	start_date DATE, 
	end_date DATE, 
	notes TEXT, 
	extra JSON, 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_projects_company_code UNIQUE (company_id, code), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT
);

CREATE TABLE purchase_order_lines (
	id CHAR(32) NOT NULL, 
	purchase_order_id CHAR(32) NOT NULL, 
	line_no INTEGER NOT NULL, 
	description TEXT NOT NULL, 
	account_id CHAR(32) NOT NULL, 
	tax_code_id CHAR(32), 
	quantity NUMERIC(18, 4) NOT NULL, 
	unit_price NUMERIC(18, 4) NOT NULL, 
	discount_pct NUMERIC(6, 2) NOT NULL, 
	line_subtotal NUMERIC(18, 2) NOT NULL, 
	line_tax NUMERIC(18, 2) NOT NULL, 
	line_total NUMERIC(18, 2) NOT NULL, 
	received_qty NUMERIC(18, 4) NOT NULL, 
	project_id CHAR(32), 
	item_id CHAR(32), 
	PRIMARY KEY (id), 
	FOREIGN KEY(purchase_order_id) REFERENCES purchase_orders (id) ON DELETE CASCADE, 
	FOREIGN KEY(account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tax_code_id) REFERENCES tax_codes (id) ON DELETE SET NULL, 
	FOREIGN KEY(project_id) REFERENCES projects (id) ON DELETE SET NULL, 
	FOREIGN KEY(item_id) REFERENCES items (id) ON DELETE SET NULL
);

CREATE TABLE purchase_orders (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	contact_id CHAR(32) NOT NULL, 
	number VARCHAR(32), 
	issue_date DATE NOT NULL, 
	expected_date DATE, 
	status VARCHAR(9) NOT NULL, 
	subtotal NUMERIC(18, 2) NOT NULL, 
	tax_total NUMERIC(18, 2) NOT NULL, 
	total NUMERIC(18, 2) NOT NULL, 
	currency VARCHAR(3) NOT NULL, 
	fx_rate NUMERIC(18, 8) NOT NULL, 
	base_subtotal NUMERIC(18, 2) NOT NULL, 
	base_tax_total NUMERIC(18, 2) NOT NULL, 
	base_total NUMERIC(18, 2) NOT NULL, 
	delivery_address TEXT, 
	notes TEXT, 
	sent_at DATETIME, 
	closed_at DATETIME, 
	cancelled_at DATETIME, 
	external_id VARCHAR(255), 
	external_source VARCHAR(64), 
	external_etag VARCHAR(255), 
	external_payload JSON, 
	version INTEGER NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_purchase_orders_company_number UNIQUE (company_id, number), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(contact_id) REFERENCES contacts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT
);

CREATE TABLE quote_lines (
	id CHAR(32) NOT NULL, 
	quote_id CHAR(32) NOT NULL, 
	line_no INTEGER NOT NULL, 
	description TEXT NOT NULL, 
	quantity NUMERIC(18, 4) NOT NULL, 
	unit_price NUMERIC(18, 4) NOT NULL, 
	tax_code_id CHAR(32), 
	line_total NUMERIC(18, 2) NOT NULL, 
	account_id CHAR(32), 
	section_label VARCHAR(255), 
	material VARCHAR(255), 
	length_note VARCHAR(255), 
	drawing_ref VARCHAR(255), 
	PRIMARY KEY (id), 
	FOREIGN KEY(quote_id) REFERENCES quotes (id) ON DELETE CASCADE, 
	FOREIGN KEY(tax_code_id) REFERENCES tax_codes (id) ON DELETE SET NULL, 
	FOREIGN KEY(account_id) REFERENCES accounts (id) ON DELETE SET NULL
);

CREATE TABLE quotes (
	id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	number VARCHAR(32), 
	customer_id CHAR(32) NOT NULL, 
	status VARCHAR(8) NOT NULL, 
	issue_date DATE NOT NULL, 
	expiry_date DATE, 
	currency VARCHAR(3) NOT NULL, 
	subtotal NUMERIC(18, 2) NOT NULL, 
	tax_total NUMERIC(18, 2) NOT NULL, 
	total NUMERIC(18, 2) NOT NULL, 
	validity_days INTEGER NOT NULL, 
	deposit_pct NUMERIC(6, 2) NOT NULL, 
	late_fee_pct_per_month NUMERIC(6, 4) NOT NULL, 
	is_supply_only BOOLEAN NOT NULL, 
	title VARCHAR(255), 
	scope TEXT, 
	notes TEXT, 
	terms TEXT, 
	version INTEGER NOT NULL, 
	accepted_at DATETIME, 
	declined_at DATETIME, 
	invoiced_at DATETIME, 
	invoice_id CHAR(32), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_quotes_tenant_number UNIQUE (tenant_id, number), 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(customer_id) REFERENCES contacts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(invoice_id) REFERENCES invoices (id) ON DELETE SET NULL
);

CREATE TABLE recurring_invoice_lines (
	id CHAR(32) NOT NULL, 
	recurring_invoice_id CHAR(32) NOT NULL, 
	line_no INTEGER NOT NULL, 
	description TEXT NOT NULL, 
	account_id CHAR(32) NOT NULL, 
	tax_code_id CHAR(32), 
	quantity NUMERIC(18, 4) NOT NULL, 
	unit_price NUMERIC(18, 4) NOT NULL, 
	discount_pct NUMERIC(6, 2) NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(recurring_invoice_id) REFERENCES recurring_invoices (id) ON DELETE CASCADE, 
	FOREIGN KEY(account_id) REFERENCES accounts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(tax_code_id) REFERENCES tax_codes (id) ON DELETE SET NULL
);

CREATE TABLE recurring_invoices (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	version INTEGER NOT NULL, 
	contact_id CHAR(32) NOT NULL, 
	name VARCHAR(128) NOT NULL, 
	frequency VARCHAR(11) NOT NULL, 
	status VARCHAR(6) NOT NULL, 
	anchor_day INTEGER, 
	next_run DATE NOT NULL, 
	end_date DATE, 
	last_run DATE, 
	due_days INTEGER NOT NULL, 
	payment_terms TEXT, 
	notes TEXT, 
	auto_post BOOLEAN NOT NULL, 
	invoices_generated INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(contact_id) REFERENCES contacts (id) ON DELETE RESTRICT
);

CREATE TABLE role_permissions (
	role VARCHAR(16) NOT NULL, 
	permission_code VARCHAR(64) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (role, permission_code), 
	FOREIGN KEY(permission_code) REFERENCES permissions (code) ON DELETE CASCADE
);

CREATE TABLE settings (
	"key" VARCHAR NOT NULL, 
	value JSON NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_by VARCHAR, 
	PRIMARY KEY ("key")
);

CREATE TABLE sql_queries (
	id CHAR(32) NOT NULL, 
	sql TEXT NOT NULL, 
	row_count INTEGER NOT NULL, 
	duration_ms INTEGER NOT NULL, 
	error TEXT, 
	performed_by VARCHAR(64), 
	executed_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id)
);

CREATE TABLE stp_submissions (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	pay_run_id CHAR(32) NOT NULL, 
	event_type VARCHAR(12) NOT NULL, 
	status VARCHAR(10) NOT NULL, 
	payload JSON NOT NULL, 
	submitted_at DATETIME, 
	submitted_by CHAR(32), 
	ato_receipt_number VARCHAR(64), 
	ato_response_payload JSON, 
	errors JSON DEFAULT '[]' NOT NULL, 
	superseded_by_id CHAR(32), 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(pay_run_id) REFERENCES pay_runs (id) ON DELETE RESTRICT, 
	FOREIGN KEY(submitted_by) REFERENCES users (id) ON DELETE SET NULL, 
	FOREIGN KEY(superseded_by_id) REFERENCES stp_submissions (id) ON DELETE SET NULL
);

CREATE TABLE stsl_coefficients (
	id CHAR(32) NOT NULL, 
	period VARCHAR(11) NOT NULL, 
	earnings_floor NUMERIC(14, 2) NOT NULL, 
	earnings_ceil NUMERIC(14, 2), 
	coef_a NUMERIC(8, 6) NOT NULL, 
	coef_b NUMERIC(14, 6) NOT NULL, 
	effective_from DATE NOT NULL, 
	effective_to DATE, 
	source_doc VARCHAR(256) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_stsl_coefficients_band_ascending CHECK (earnings_ceil IS NULL OR earnings_ceil > earnings_floor), 
	CONSTRAINT ck_stsl_coefficients_dates_ascending CHECK (effective_to IS NULL OR effective_to >= effective_from), 
	CONSTRAINT ck_stsl_coefficients_coef_a_nonneg CHECK (coef_a >= 0)
);

CREATE TABLE super_funds (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	name VARCHAR(128) NOT NULL, 
	usi VARCHAR(11), 
	spin VARCHAR(20), 
	is_smsf BOOLEAN NOT NULL, 
	employer_abn VARCHAR(14), 
	esa VARCHAR(16), 
	smsf_bsb_encrypted TEXT, 
	smsf_account_number_encrypted TEXT, 
	smsf_account_name_encrypted TEXT, 
	is_default BOOLEAN NOT NULL, 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_super_funds_smsf_required_fields CHECK (is_smsf = false OR (employer_abn IS NOT NULL AND esa IS NOT NULL)), 
	CONSTRAINT ck_super_funds_apra_requires_usi CHECK (is_smsf = true OR usi IS NOT NULL), 
	CONSTRAINT ck_super_funds_usi_length CHECK (usi IS NULL OR length(usi) = 11), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT
);

CREATE TABLE tax_codes (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	code VARCHAR(16) NOT NULL, 
	name VARCHAR NOT NULL, 
	rate NUMERIC(6, 3) NOT NULL, 
	tax_system VARCHAR(16) NOT NULL, 
	reporting_type VARCHAR(32) NOT NULL, 
	description VARCHAR, 
	version INTEGER NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT
);

CREATE TABLE tax_periods (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	jurisdiction VARCHAR(3) NOT NULL, 
	period_type VARCHAR(11) NOT NULL, 
	period_start DATE NOT NULL, 
	period_end DATE NOT NULL, 
	status VARCHAR(6) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_tax_periods_company_jur_start UNIQUE (company_id, jurisdiction, period_start), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT
);

CREATE TABLE tax_returns (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	jurisdiction VARCHAR(3) NOT NULL, 
	period_id CHAR(32) NOT NULL, 
	return_type VARCHAR(32) NOT NULL, 
	figures JSON NOT NULL, 
	generated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	generated_by_user_id CHAR(32), 
	status VARCHAR(8) NOT NULL, 
	lodgement_record_id CHAR(32), 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(period_id) REFERENCES tax_periods (id) ON DELETE RESTRICT, 
	FOREIGN KEY(generated_by_user_id) REFERENCES users (id) ON DELETE SET NULL, 
	FOREIGN KEY(lodgement_record_id) REFERENCES lodgement_records (id) ON DELETE SET NULL
);

CREATE TABLE tenants (
	id CHAR(32) NOT NULL, 
	name TEXT NOT NULL, 
	slug VARCHAR(128) NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	edition VARCHAR(16) DEFAULT 'community' NOT NULL, 
	stripe_customer_id VARCHAR(64), 
	stripe_subscription_id VARCHAR(64), 
	PRIMARY KEY (id), 
	UNIQUE (slug)
);

CREATE TABLE time_entries (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	user_id CHAR(32) NOT NULL, 
	contact_id CHAR(32), 
	work_date DATE NOT NULL, 
	hours NUMERIC(5, 2) NOT NULL, 
	start_time TIME, 
	end_time TIME, 
	break_minutes INTEGER DEFAULT '0' NOT NULL, 
	description TEXT DEFAULT '' NOT NULL, 
	project_id CHAR(32), 
	department_id CHAR(32), 
	cost_centre_id CHAR(32), 
	billable BOOLEAN DEFAULT 'false' NOT NULL, 
	rate NUMERIC(10, 4), 
	invoice_line_id CHAR(32), 
	approval_status VARCHAR(9) DEFAULT 'DRAFT' NOT NULL, 
	submitted_at DATETIME, 
	approved_at DATETIME, 
	approved_by CHAR(32), 
	rejection_reason TEXT, 
	version INTEGER DEFAULT '1' NOT NULL, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_time_entries_hours_positive CHECK (hours > 0), 
	CONSTRAINT ck_time_entries_clock_pair CHECK ((start_time IS NULL) = (end_time IS NULL)), 
	CONSTRAINT ck_time_entries_break_nonneg CHECK (break_minutes >= 0), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(user_id) REFERENCES users (id) ON DELETE RESTRICT, 
	FOREIGN KEY(contact_id) REFERENCES contacts (id) ON DELETE RESTRICT, 
	FOREIGN KEY(project_id) REFERENCES projects (id) ON DELETE SET NULL, 
	FOREIGN KEY(department_id) REFERENCES departments (id) ON DELETE SET NULL, 
	FOREIGN KEY(cost_centre_id) REFERENCES cost_centres (id) ON DELETE SET NULL, 
	FOREIGN KEY(invoice_line_id) REFERENCES invoice_lines (id) ON DELETE SET NULL, 
	FOREIGN KEY(approved_by) REFERENCES users (id) ON DELETE SET NULL
);

CREATE TABLE trust_distributions (
	id CHAR(32) NOT NULL, 
	company_id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	financial_year INTEGER NOT NULL, 
	distribution_date DATE NOT NULL, 
	resolution_minuted_date DATE, 
	status VARCHAR(16) NOT NULL, 
	total_amount NUMERIC(14, 2) NOT NULL, 
	total_franking_credits NUMERIC(14, 2) NOT NULL, 
	notes TEXT, 
	journal_entry_id CHAR(32), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES companies (id) ON DELETE CASCADE, 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(journal_entry_id) REFERENCES journal_entries (id) ON DELETE SET NULL
);

CREATE TABLE user_permissions (
	user_id CHAR(32) NOT NULL, 
	permission_code VARCHAR(64) NOT NULL, 
	granted BOOLEAN DEFAULT 'true' NOT NULL, 
	granted_by VARCHAR(64), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (user_id, permission_code), 
	FOREIGN KEY(user_id) REFERENCES users (id) ON DELETE CASCADE, 
	FOREIGN KEY(permission_code) REFERENCES permissions (code) ON DELETE CASCADE
);

CREATE TABLE user_webauthn_credentials (
	id CHAR(32) DEFAULT (gen_random_uuid()) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	user_id CHAR(32) NOT NULL, 
	credential_id BLOB NOT NULL, 
	public_key BLOB NOT NULL, 
	sign_count BIGINT DEFAULT '0' NOT NULL, 
	transports JSON NOT NULL, 
	aaguid BLOB NOT NULL, 
	friendly_name VARCHAR(64) DEFAULT 'Security key' NOT NULL, 
	last_used_at DATETIME, 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	FOREIGN KEY(user_id) REFERENCES users (id) ON DELETE CASCADE, 
	UNIQUE (credential_id)
);

CREATE TABLE users (
	id CHAR(32) NOT NULL, 
	tenant_id CHAR(32) NOT NULL, 
	username VARCHAR(64) NOT NULL, 
	display_name VARCHAR(128), 
	email VARCHAR(255), 
	role VARCHAR(16) DEFAULT 'viewer' NOT NULL, 
	last_seen_at DATETIME, 
	preferred_theme VARCHAR(32), 
	created_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	updated_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	archived_at DATETIME, 
	version INTEGER DEFAULT '1' NOT NULL, 
	password_hash VARCHAR(255), 
	email_verified_at DATETIME, 
	email_verification_token_hash CHAR(64), 
	email_verification_expires_at DATETIME, 
	password_reset_token_hash CHAR(64), 
	password_reset_expires_at DATETIME, 
	magic_link_token_hash CHAR(64), 
	magic_link_expires_at DATETIME, 
	password_version INTEGER DEFAULT '0' NOT NULL, 
	signup_plan VARCHAR(16), 
	fido2_registered_at DATETIME, 
	fido2_credential_count INTEGER DEFAULT '0' NOT NULL, 
	launch_promo_jwt TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(tenant_id) REFERENCES tenants (id) ON DELETE RESTRICT, 
	UNIQUE (username)
);

